import React, { useEffect, useState } from 'react';
import Select from 'react-select';
import './CreateCombinedMaterial.css'; // Import CSS for styling

const CombinedMaterialInputForm = ({
  onClose,
  apiBaseUrl,
  fetchData,
  editingMaterial,
  closeCreateCombinedMaterialForm
}) => {
  const [combinedMaterialName, setCombinedMaterialName] = useState('');
  const [combinedMaterialDescription, setCombinedMaterialDescription] = useState('');
  const [selectedMaterials, setSelectedMaterials] = useState([{ materialId: '', multiplier: 1, unitPrice: 0 }]);
  const [materials, setMaterials] = useState([]); // Assume this is fetched or passed down as props

  useEffect(() => {
    if (editingMaterial) {
      // Load the editing material's data into the form
      setCombinedMaterialName(editingMaterial.name);
      setCombinedMaterialDescription(editingMaterial.description);
      // Assume editingMaterial contains an array of selectedMaterials
      setSelectedMaterials(editingMaterial.selectedMaterials || []);
    }
    // Fetch materials list for the select dropdown
    const fetchMaterials = async () => {
      try {
        const response = await fetch(`${apiBaseUrl}/materials`);
        const data = await response.json();
        setMaterials(data);
      } catch (error) {
        console.error("Failed to fetch materials", error);
      }
    };
    fetchMaterials();
  }, [editingMaterial, apiBaseUrl]);

  const handleMaterialChange = (index, materialId) => {
    const updatedMaterials = selectedMaterials.map((material, idx) =>
      idx === index ? { ...material, materialId } : material
    );
    setSelectedMaterials(updatedMaterials);
  };

  const handleMultiplierChange = (index, multiplier) => {
    const updatedMaterials = selectedMaterials.map((material, idx) =>
      idx === index ? { ...material, multiplier: parseFloat(multiplier) || 1 } : material
    );
    setSelectedMaterials(updatedMaterials);
  };

  const addMaterial = () => {
    setSelectedMaterials([...selectedMaterials, { materialId: '', multiplier: 1, unitPrice: 0 }]);
  };

  const removeMaterial = (index) => {
    setSelectedMaterials(selectedMaterials.filter((_, idx) => idx !== index));
  };

  const han = async () => {
    try {
      const payload = {
        name: combinedMaterialName,
        description: combinedMaterialDescription,
        submaterials: selectedMaterials
      };
      await fetch(`${apiBaseUrl}/saveCombinedMaterial`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify(payload)
      });
      alert('Combined material saved successfully!');
      fetchData(); // Fetch the updated list of combined materials
      closeCreateCombinedMaterialForm();
    } catch (error) {
      alert(`Error: ${error.message}`);
    }
  };

  const materialOptions = materials.map(material => ({
    value: material.matid,
    label: material.name
  }));

    return (
        <div className="material-input-form">
            
        <h3>Combine Materials</h3>
        <span className="close-popup" onClick={onClose}>
                &times;
            </span>
        <div className="form-row">
            <div className="form-group">
                <label htmlFor="comboName">Combo Name</label>
                <input 
                    id="comboName"
                    type="text"
                    value={combinedMaterialName}
                    onChange={(e) => setCombinedMaterialName(e.target.value)}
                    placeholder="Enter combined material name"
                    className="form-control"
                />
            </div>
            <div className="form-group">
                <label htmlFor="description">Description</label>
                <textarea 
                    id="description"
                    value={combinedMaterialDescription}
                    onChange={(e) => setcombinedMaterialDescription(e.target.value)}
                    placeholder="Enter Description"
                    className="form-control"
                />
            </div>
        </div>
        
        {selectedMaterials.map((selection, index) => (
            <div key={index} className="material-selection">
                <div className="form-row">
                    <div className="form-group">
                        <label>Material</label>
                        <select
                            value={selection.materialId}
                            onChange={(e) => handleMaterialChange(index, e.target.value)}
                            className="form-control"
                        >
                            <option value="">Select Material</option>
                            {materials.map(material => (
                                <option key={material.matid} value={material.matid}>{material.name}</option>
                            ))}
                        </select>
                    </div>
                    <div className="form-group">
                        <label>Multiplier</label>
                        <input
                            type="number"
                            value={selection.multiplier}
                            onChange={(e) => handleMultiplierChange(index, e.target.value)}
                            className="form-control"
                        />
                    </div>
                    <div className="price-remove-container">
                        <div className="unit-price">
                            <span>Unit Price: {selection.unitPrice.toFixed(2)}</span>
                        </div>
                    </div>
                    <div className="price-remove-container">
                        {selectedMaterials.length > 1 && (
                            <button className="remove-btn" onClick={() => removeMaterial(index)}>Remove</button>
                        )}
                    </div>
                </div>
            </div>
        ))}

        <button className="btn btn-primary add-btn" onClick={addMaterial} >Add Material</button>
        <button className="btn btn-success save-btn" onClick={handleSave}>Save Combined Material</button>
    </div>
    
    );
};

export default CombinedMaterialInputForm;
